#define OPEN
#define ITERATION
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda_runtime.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

void random_matrix(float *I, int rows, int cols);

static void cuda_check(cudaError_t err, const char *msg)
{
	if (err != cudaSuccess) {
		fprintf(stderr, "CUDA error at %s: %s\n", msg, cudaGetErrorString(err));
		exit(1);
	}
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> \t - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

	exit(1);
}

__global__ void srad_prepare_kernel(const float *J, float *dN, float *dS, float *dW, float *dE, float *c, int rows, int cols, float q0sqr)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;
		float Jc = J[k];

		int iN = (i == 0) ? 0 : (i - 1);
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jW = (j == 0) ? 0 : (j - 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float dNk = J[iN * cols + j] - Jc;
		float dSk = J[iS * cols + j] - Jc;
		float dWk = J[i * cols + jW] - Jc;
		float dEk = J[i * cols + jE] - Jc;

		dN[k] = dNk;
		dS[k] = dSk;
		dW[k] = dWk;
		dE[k] = dEk;

		float G2 = (dNk * dNk + dSk * dSk + dWk * dWk + dEk * dEk) / (Jc * Jc);
		float L = (dNk + dSk + dWk + dEk) / Jc;

		float num = (0.5f * G2) - (0.0625f * (L * L));
		float den = 1.0f + (0.25f * L);
		float qsqr = num / (den * den);

		den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
		float ck = 1.0f / (1.0f + den);

		if (ck < 0.0f) ck = 0.0f;
		else if (ck > 1.0f) ck = 1.0f;

		c[k] = ck;
	}
}

__global__ void srad_update_kernel(float *J, const float *dN, const float *dS, const float *dW, const float *dE, const float *c, int rows, int cols, float lambda)
{
	int j = blockIdx.x * blockDim.x + threadIdx.x;
	int i = blockIdx.y * blockDim.y + threadIdx.y;

	if (i < rows && j < cols) {
		int k = i * cols + j;
		int iS = (i == rows - 1) ? (rows - 1) : (i + 1);
		int jE = (j == cols - 1) ? (cols - 1) : (j + 1);

		float cN = c[k];
		float cS = c[iS * cols + j];
		float cW = c[k];
		float cE = c[i * cols + jE];

		float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];
		J[k] = J[k] + 0.25f * lambda * D;
	}
}

int main(int argc, char* argv[])
{
	int rows, cols, size_I, size_R, niter = 10, iter, k;
	float *I, *J, q0sqr, sum, sum2, tmp, meanROI, varROI;
	int r1, r2, c1, c2;
	float lambda;
	int nthreads;

	float *d_J = NULL, *d_c = NULL, *d_dN = NULL, *d_dS = NULL, *d_dW = NULL, *d_dE = NULL;

	if (argc == 10)
	{
		rows = atoi(argv[1]);
		cols = atoi(argv[2]);
		if ((rows % 16 != 0) || (cols % 16 != 0)) {
			fprintf(stderr, "rows and cols must be multiples of 16\n");
			exit(1);
		}
		r1 = atoi(argv[3]);
		r2 = atoi(argv[4]);
		c1 = atoi(argv[5]);
		c2 = atoi(argv[6]);
		nthreads = atoi(argv[7]);
		lambda = (float)atof(argv[8]);
		niter = atoi(argv[9]);
	}
	else {
		usage(argc, argv);
	}

	(void)nthreads;

	size_I = cols * rows;
	size_R = (r2 - r1 + 1) * (c2 - c1 + 1);

	I = (float *)malloc(size_I * sizeof(float));
	J = (float *)malloc(size_I * sizeof(float));

	if (I == NULL || J == NULL) {
		fprintf(stderr, "host memory allocation failed\n");
		free(I);
		free(J);
		return 1;
	}

	printf("Randomizing the input matrix\n");

	random_matrix(I, rows, cols);

	for (k = 0; k < size_I; k++) {
		J[k] = (float)exp((double)I[k]);
	}

	cuda_check(cudaMalloc((void **)&d_J, size_I * sizeof(float)), "cudaMalloc d_J");
	cuda_check(cudaMalloc((void **)&d_c, size_I * sizeof(float)), "cudaMalloc d_c");
	cuda_check(cudaMalloc((void **)&d_dN, size_I * sizeof(float)), "cudaMalloc d_dN");
	cuda_check(cudaMalloc((void **)&d_dS, size_I * sizeof(float)), "cudaMalloc d_dS");
	cuda_check(cudaMalloc((void **)&d_dW, size_I * sizeof(float)), "cudaMalloc d_dW");
	cuda_check(cudaMalloc((void **)&d_dE, size_I * sizeof(float)), "cudaMalloc d_dE");

	cuda_check(cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice), "cudaMemcpy H2D J");

	printf("Start the SRAD main loop\n");

	dim3 block(BLOCK_SIZE, BLOCK_SIZE);
	dim3 grid((cols + block.x - 1) / block.x, (rows + block.y - 1) / block.y);

#ifdef ITERATION
	for (iter = 0; iter < niter; iter++) {
#endif
		cuda_check(cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy D2H J");

		sum = 0.0f;
		sum2 = 0.0f;
		for (int i = r1; i <= r2; i++) {
			for (int j = c1; j <= c2; j++) {
				tmp = J[i * cols + j];
				sum += tmp;
				sum2 += tmp * tmp;
			}
		}
		meanROI = sum / size_R;
		varROI = (sum2 / size_R) - meanROI * meanROI;
		q0sqr = varROI / (meanROI * meanROI);

		srad_prepare_kernel<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, q0sqr);
		cuda_check(cudaGetLastError(), "srad_prepare_kernel launch");

		srad_update_kernel<<<grid, block>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, rows, cols, lambda);
		cuda_check(cudaGetLastError(), "srad_update_kernel launch");
#ifdef ITERATION
	}
#endif

	cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

#ifdef OUTPUT
	cuda_check(cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost), "cudaMemcpy final D2H J");
	for (int i = 0; i < rows; i++) {
		for (int j = 0; j < cols; j++) {
			printf("%.5f ", J[i * cols + j]);
		}
		printf("\n");
	}
#endif

	printf("Computation Done\n");

	cudaFree(d_J);
	cudaFree(d_c);
	cudaFree(d_dN);
	cudaFree(d_dS);
	cudaFree(d_dW);
	cudaFree(d_dE);

	free(I);
	free(J);

	return 0;
}

